import './App.css'; 
import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate } from 'react-router-dom';
import axios from 'axios';
import Login from './pages/Login';
import Signup from './pages/Signup';
import RegisterComplaint from './pages/RegisterComplaint';

function App() {
  const [complaints, setComplaints] = useState([]);
  const [token, setToken] = useState(localStorage.getItem('token'));
  // Admin check ke liye naya state
  const [isAdmin, setIsAdmin] = useState(localStorage.getItem('is_admin') === 'true');

  // API Call setup with Headers
  const fetchComplaints = async () => {
    try {
      const response = await axios.get('http://127.0.0.1:8000/api/complaints/', {
        headers: { Authorization: `Bearer ${token}` } // Token connection ke liye zaroori hai
      });
      setComplaints(response.data);
    } catch (err) {
      console.error("Connectivity Issue: Backend response nahi de raha", err);
    }
  };

  useEffect(() => {
    if (token) {
      fetchComplaints();
    }
  }, [token]);

  const handleResolve = async (id) => {
    try {
      await axios.put(`http://127.0.0.1:8000/api/complaints/${id}/resolve`, {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert("Complaint Resolved!");
      fetchComplaints();
    } catch (err) {
      alert("Resolution failed: Connection or Permission error");
    }
  };

  const handleLogout = () => {
    localStorage.clear(); // Saara data clear karein
    setToken(null);
    setIsAdmin(false);
    window.location.href = "/login";
  };

  return (
    <Router>
      <nav className="navbar">
        <div className="logo-section">
          <div className="logo-circle">G</div>
          <Link to="/" className="brand-name">
            Grievance<span style={{ color: '#ffcc00' }}>Portal</span>
          </Link>
        </div>

        <div className="nav-links">
          {!token ? (
            <>
              <Link to="/login">Login</Link>
              <Link to="/signup" className="signup-btn">Signup</Link>
            </>
          ) : (
            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
              <span className="user-badge">{isAdmin ? "Admin Mode" : "User Mode"}</span>
              <button onClick={handleLogout} className="logout-btn">Logout</button>
            </div>
          )}
        </div>
      </nav>

      <Routes>
        <Route path="/login" element={!token ? <Login setToken={setToken} setIsAdmin={setIsAdmin} /> : <Navigate to="/" />} />
        <Route path="/signup" element={!token ? <Signup /> : <Navigate to="/" />} />

        <Route path="/" element={token ? (
          <div className="dashboard-container">
            <h1 className="page-title">{isAdmin ? "Admin Control Panel" : "Your Dashboard"}</h1>
            <hr />

            {/* Sirf User ko complaint register karne ka option dikhega */}
            {!isAdmin && <RegisterComplaint onRefresh={fetchComplaints} token={token} />}

            <div className="complaints-section">
              <h3>{isAdmin ? "All User Complaints:" : "Your Recent Complaints:"}</h3>
              {complaints.length === 0 ? (
                <p className="no-data">Koi records nahi mile.</p>
              ) : (
                <ul className="complaint-list">
                  {complaints.map((c) => (
                    <li key={c.id} className="complaint-card">
                      <div className="card-header">
                        <div>
                          <b className="complaint-title">{c.title}</b> <br />
                          <small className="complaint-cat">Category: {c.category}</small>
                        </div>
                        <div className="card-actions">
                          <span className={`status-badge ${c.status.toLowerCase()}`}> 
                            {c.status} 
                          </span>
                          {/* Resolve button sirf Admin ko aur sirf Pending status par dikhega */}
                          {isAdmin && c.status === 'Pending' && (
                            <button onClick={() => handleResolve(c.id)} className="resolve-btn">
                              Mark Resolved
                            </button>
                          )}
                        </div>
                      </div>
                      <p className="complaint-desc">{c.description}</p>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        ) : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
